INSERT INTO `pd_review` VALUES (1,1,1,5.0,'超級實用的旅行組合！','包裝精美，牙刷質量很好，牙膏也不會漏。收納盒設計很貼心，放在行李箱不佔空間。出差旅行必備！','[\"https://example.com/images/review1_1.jpg\", \"https://example.com/images/review1_2.jpg\"]',1,15,1,'2025-10-15 18:00:00','2025-10-18 00:54:21'),(2,1,2,4.5,'性價比高','整體來說很不錯，唯一小缺點是牙刷的刷毛稍微硬了一點，但其他都很滿意。',NULL,1,8,1,'2025-10-15 22:30:00','2025-10-18 00:54:21'),(3,1,3,3.0,'很棒','基本功能都有，但收納盒的扣子不太好開。',NULL,0,3,1,'2025-10-16 17:15:00','2025-10-30 02:28:22'),(4,6,1,5.0,'充電神器！','容量超大，可以充滿我的iPhone 3次還有剩。支援快充真的很方便，出門再也不用擔心手機沒電了！','[\"https://example.com/images/review6_1.jpg\"]',1,42,1,'2025-10-15 00:20:00','2025-10-18 00:54:21'),(5,6,2,4.5,'充電速度快','雙USB輸出很實用，可以同時充兩個設備。LED電量顯示清楚，但稍微有點重量。',NULL,1,22,1,'2025-10-15 19:00:00','2025-10-18 00:54:21'),(6,6,3,5.0,'旅行必備','帶去日本旅遊，每天充手機和相機都沒問題，真的很耐用！','[\"https://example.com/images/review6_3.jpg\"]',1,18,1,'2025-10-16 18:30:00','2025-10-18 00:54:21'),(7,7,2,5.0,'出國必備神器','去了歐洲、日本都能用，內建USB充電孔超方便，不用再帶一堆轉接頭了！','[\"https://example.com/images/review7_1.jpg\"]',1,35,1,'2025-10-14 17:30:00','2025-10-18 00:54:21'),(8,7,3,4.5,'非常實用','適用大部分國家，USB充電功能很貼心，唯一缺點是體積稍大。',NULL,1,12,1,'2025-10-15 21:45:00','2025-10-18 00:54:21'),(9,8,3,5.0,'音質超讚！','降噪效果很好，搭飛機時完全不會被引擎聲打擾。電池續航力強，充電盒又多提供24小時，超滿意！','[\"https://example.com/images/review8_1.jpg\", \"https://example.com/images/review8_2.jpg\"]',1,56,1,'2025-10-13 23:00:00','2025-10-18 00:54:21'),(10,8,1,4.5,'性價比不錯','音質清晰，連線穩定，IPX5防水很實用。唯一小缺點是耳機稍微大了一點。',NULL,1,28,1,'2025-10-14 19:20:00','2025-10-18 00:54:21'),(11,8,2,5.0,'推薦購買','降噪功能真的很強，通勤時聽音樂超享受，充電速度也很快！',NULL,1,19,1,'2025-10-16 00:30:00','2025-10-18 00:54:21'),(12,11,1,4.5,'節省空間好幫手','不需要抽氣機，用手壓就能排氣，真的節省很多行李空間！材質也很耐用。','[\"https://example.com/images/review11_1.jpg\"]',1,25,1,'2025-10-15 20:00:00','2025-10-18 00:54:21'),(13,11,3,4.0,'實用但需要技巧','第一次用需要練習一下，熟悉後很方便。建議不要裝太滿，比較好壓縮。',NULL,1,10,1,'2025-10-16 16:30:00','2025-10-18 00:54:21'),(14,21,1,5.0,'露營神器！','真的很輕只有2.5kg！搭建超快速，防水效果也很好。去了三次露營都沒問題，強力推薦！','[\"https://example.com/images/review21_1.jpg\", \"https://example.com/images/review21_2.jpg\", \"https://example.com/images/review21_3.jpg\"]',1,67,1,'2025-10-16 22:00:00','2025-10-18 00:54:21'),(15,21,2,4.5,'很棒的帳篷','空間對兩個人來說剛剛好，通風設計不錯。唯一缺點是收納袋有點小，不太好收。',NULL,1,31,1,'2025-10-17 00:45:00','2025-10-18 00:54:21'),(16,21,3,5.0,'超值！','這個價格能買到這麼好的帳篷真的很划算，下大雨也沒有漏水，讚！',NULL,1,24,1,'2025-10-17 17:00:00','2025-10-18 00:54:21'),(17,27,3,5.0,'登山好夥伴','背負系統設計得很好，長時間背著也不會累。防水拉鍊很實用，多口袋設計方便分類。','[\"https://example.com/images/review27_1.jpg\"]',1,38,1,'2025-10-15 18:30:00','2025-10-18 00:54:21'),(18,27,2,4.5,'品質不錯','容量夠大，材質耐用。肩帶很舒適，但腰帶的扣環有點硬。',NULL,1,15,1,'2025-10-16 19:00:00','2025-10-18 00:54:21'),(19,36,3,5.0,'防曬效果超好','去海邊玩一整天都沒有曬傷！質地清爽不黏膩，而且防水抗汗，游泳也不用擔心。','[\"https://example.com/images/review36_1.jpg\"]',1,45,1,'2025-10-16 21:30:00','2025-10-18 00:54:21'),(20,36,1,4.5,'敏感肌適用','無香料配方很溫和，敏感肌用了也不會過敏。唯一缺點是要多抹幾次才能完全推開。',NULL,1,21,1,'2025-10-16 23:00:00','2025-10-18 00:54:21'),(21,41,3,5.0,'超好穿！','彈性很好，穿起來很舒服。防曬UPF50+真的有效，游完泳皮膚也沒曬傷。乾得很快！','[\"https://example.com/images/review41_1.jpg\", \"https://example.com/images/review41_2.jpg\"]',1,29,1,'2025-10-17 18:15:00','2025-10-18 00:54:21'),(22,41,2,4.5,'質感不錯','材質摸起來很舒服，抗氯防曬功能都很好。版型合身但不會太緊。',NULL,1,16,1,'2025-10-17 19:30:00','2025-10-18 00:54:21');
/*!40000 ALTER TABLE `pd_review` ENABLE KEYS */;
UNLOCK TABLES;

